1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE = 0.1;
3	
4	interface QuoteStep {
5	  op: "quote";
6	  items: { type: string }[];
7	}
8	
9	interface Scenario {
10	  customer: { yearsWithMHPCO: number };
11	  steps: QuoteStep[];
12	}
13	
14	const BASE_PREMIUMS: Record<string, number> = {
15	  sword: 100,
16	  amulet: 60,
17	  staff: 80,
18	  potion: 40,
19	  rune: 25,
20	  moonstone: 25,
21	};
22	
23	const BLOCK_TYPE = "rune";
24	const BLOCK_SIZE = 3;
25	const BLOCK_PREMIUM = 60;
26	
27	const formsBlock = (type: string, count: number): boolean =>
28	  type === BLOCK_TYPE && count === BLOCK_SIZE;
29	
30	const typeBasePremium = (type: string, count: number): number => {
31	  if (formsBlock(type, count)) return BLOCK_PREMIUM;
32	  return count * BASE_PREMIUMS[type];
33	};
34	
35	const policyBasePremium = (items: { type: string }[]): number => {
36	  const counts = new Map<string, number>();
37	  for (const item of items) {
38	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
39	  }
40	  return [...counts].reduce(
41	    (base, [type, count]) => base + typeBasePremium(type, count),
42	    0,
43	  );
44	};
45	
46	// Premiums round up (in the MHPCO's favor); toFixed guards against
47	// floating-point error nudging an exact value over an integer boundary.
48	const roundUpPremium = (amount: number): number =>
49	  Math.ceil(Number(amount.toFixed(6)));
50	
51	const quotePremium = (step: QuoteStep): number => {
52	  const base = policyBasePremium(step.items);
53	  const total = base * (1 + FIRST_INSURANCE_SURCHARGE) + PROCESSING_FEE;
54	  return roundUpPremium(total);
55	};
56	
57	export const runScenario = (scenario: Scenario): { results: unknown[] } => {
58	  return { results: scenario.steps.map((step) => ({ premium: quotePremium(step) })) };
59	};
